import React from 'react';

class Test extends React.Component{
  render() {
    const { projects } = this.props;
    const projectList = projects.map(project => {
        return (
          <div className="project">
          <h2> Name: { project.name } </h2>
          </div>
        )
    })
    return (
          <div id="about-page">
            { projectList }
          </div>
    )
  }
}

export default Test;
